import { afterAll, beforeAll, test } from "vitest";
import assert from "node:assert/strict";
import fs from "node:fs";
import path from "node:path";

import { ProjectRegistry, SymlinkProjectRootError } from "../../src/server/agent/project-registry.js";
import { installScopedMemFs } from "./helpers/scoped-memfs.js";

const ROOT = path.resolve("/memfs/project-registry-symlink");
const TARGET = path.join(ROOT, "canonical");
const LINK = path.join(ROOT, "via-symlink");
let stateSequence = 0;
let restoreFs: () => void;

beforeAll(() => {
	const scoped = installScopedMemFs([
		"accessSync", "existsSync", "mkdirSync", "readFileSync", "readdirSync", "realpathSync",
		"renameSync", "rmdirSync", "statSync", "statfsSync", "symlinkSync", "writeFileSync",
	]);
	restoreFs = scoped.restore;
	fs.mkdirSync(path.join(TARGET, "sub"), { recursive: true });
	fs.symlinkSync(TARGET, LINK, "dir");
});

afterAll(() => restoreFs());

/** Make a fresh isolated in-memory state dir for each registry. */
function makeStateDir(): string {
	return path.join(ROOT, `state-${stateSequence++}`);
}

test("register-symlink-throws: registering with a symlink path throws SymlinkProjectRootError", () => {
	const reg = new ProjectRegistry(makeStateDir());
	let caught: unknown;
	try {
		reg.register("p", LINK);
	} catch (err) {
		caught = err;
	}
	assert.ok(caught instanceof SymlinkProjectRootError, "expected SymlinkProjectRootError");
	const e = caught as SymlinkProjectRootError;
	assert.equal(e.code, "symlink_root");
	assert.equal(path.resolve(e.canonical), path.resolve(TARGET));
});

test("register-symlink-accept-canonical: acceptCanonical=true stores canonical path", () => {
	const reg = new ProjectRegistry(makeStateDir());
	const proj = reg.register("p", LINK, { acceptCanonical: true });
	assert.equal(path.resolve(proj.rootPath), path.resolve(TARGET));
});

test("findByCwd-via-symlink: cwd reached through symlink resolves to canonically-registered project", () => {
	const reg = new ProjectRegistry(makeStateDir());
	const proj = reg.register("p", TARGET);
	const found = reg.findByCwd(path.join(LINK, "sub"));
	assert.ok(found, "expected findByCwd to resolve through the symlink");
	assert.equal(found.id, proj.id);
});

test("findByCwd-canonical-still-works: no regression for canonical-path lookups", () => {
	const reg = new ProjectRegistry(makeStateDir());
	const proj = reg.register("p", TARGET);
	const found = reg.findByCwd(path.join(TARGET, "sub"));
	assert.ok(found);
	assert.equal(found.id, proj.id);
});
